5: use std::cell::RefCell;
6: 
7: use cssparser::SourceLocation;
8: use servo_arc::Arc;
9: use style::context::QuirksMode;
10: use style::error_reporting::{ContextualParseError, ParseErrorReporter};
11: use style::media_queries::MediaList;
12: use style::shared_lock::SharedRwLock;
13: use style::stylesheets::{
14:     AllowImportRules, Origin, Stylesheet, StylesheetInDocument, UrlExtraData,
15: };
16: use url::Url;
17: 
18: #[derive(Debug)]
19: struct CSSError {
20:     pub url: Arc<Url>,
21:     pub line: u32,
22:     pub column: u32,
23:     pub message: String,
24: }
25: 
26: struct TestingErrorReporter {
27:     errors: RefCell<Vec<CSSError>>,
28: }
29: 
30: impl TestingErrorReporter {
31:     pub fn new() -> Self {
32:         TestingErrorReporter {
33:             errors: RefCell::new(Vec::new()),
34:         }
35:     }
36: 
37:     fn assert_messages_contain(&self, expected_errors: &[(u32, u32, &str)]) {
38:         let errors = self.errors.borrow();
39:         for (i, (error, &(line, column, message))) in errors.iter().zip(expected_errors).enumerate()
40:         {
41:             assert_eq!(
42:                 (error.line, error.column),
43:                 (line, column),
44:                 "line/column numbers of the {}th error: {:?}",
45:                 i + 1,
46:                 error.message
47:             );
48:             assert!(
49:                 error.message.contains(message),
50:                 "{:?} does not contain {:?}",
51:                 error.message,
52:                 message
53:             );
54:         }
55:         if errors.len() < expected_errors.len() {
56:             panic!("Missing errors: {:#?}", &expected_errors[errors.len()..]);
57:         }
58:         if errors.len() > expected_errors.len() {
59:             panic!("Extra errors: {:#?}", &errors[expected_errors.len()..]);
60:         }
61:     }
62: }
63: 
64: impl ParseErrorReporter for TestingErrorReporter {
65:     fn report_error(
66:         &self,
67:         url: &UrlExtraData,
68:         location: SourceLocation,
69:         error: ContextualParseError,
70:     ) {
71:         self.errors.borrow_mut().push(CSSError {
